// 1. Get all rows from the Google Sheet
const allDocs = $input.all();

// 2. Calculate the exact timestamp for 24 hours ago
const yesterday = new Date(new Date().getTime() - (24 * 60 * 60 * 1000));

// 3. Filter for only documents processed in the last 24 hours
const recentDocs = allDocs.filter(item => {
  // Grab the date string from your sheet and turn it into a JS Date object
  const docDate = new Date(item.json.processed_at); 
  return docDate >= yesterday;
});

// 4. Handle the case where no documents were processed
if (recentDocs.length === 0) {
  return [{ json: { emailBody: "<p>No documents were processed in the last 24 hours.</p>" } }];
}

// 5. Build a nice HTML summary table
let html = "<h2>Daily Document Processing Summary</h2>";
html += "<p>Here are the documents processed by the AI pipeline over the last 24 hours:</p>";
html += "<table border='1' cellpadding='8' style='border-collapse: collapse; text-align: left;'>";
html += "<tr style='background-color: #f2f2f2;'><th>File</th><th>Type</th><th>Dept</th><th>Sensitivity</th><th>Routing</th></tr>";

recentDocs.forEach(item => {
  const doc = item.json;
  html += `<tr>
    <td><b>${doc.filename || 'Unknown'}</b></td>
    <td>${doc.classification || '-'}</td>
    <td>${doc.department || '-'}</td>
    <td>${doc.sensitivity || '-'}</td>
    <td>${doc.routing_tag || '-'}</td>
  </tr>`;
});

html += "</table>";
html += `<br><p>Total documents processed: <b>${recentDocs.length}</b></p>`;

return [{ json: { emailBody: html } }];
